int longestCommonSubsequence(string text1, string text2) &#123;
    const int n1&#x3D;text1.size(),n2&#x3D;text2.size();
    vector&lt;vector&lt;int&gt;&gt; dp(n1+1,vector&lt;int&gt;(n2+1,0)); &#x2F;&#x2F;防止讨论i-1&lt;0情况
    for(int i&#x3D;1;i&lt;&#x3D;n1;++i)
        for(int j&#x3D;1;j&lt;&#x3D;n2;++j)&#123;
            if(text1[i-1] &#x3D;&#x3D; text2[j-1])
                dp[i][j] &#x3D; dp[i-1][j-1]+1;
            else
                dp[i][j] &#x3D; max(dp[i-1][j],dp[i][j-1]);
        &#125;
