int knapsack(vector&lt;int&gt; weights, vector&lt;int&gt; values, int N, int W) &#123;
    vector&lt;vector&lt;int&gt;&gt; dp(N + 1, vector&lt;int&gt;(W + 1, 0));
    for (int i &#x3D; 1; i &lt;&#x3D; N; ++i) &#123;
        int w &#x3D; weights[i-1], v &#x3D; values[i-1];
        for (int j &#x3D; 1; j &lt;&#x3D; W; ++j)
            if (j &gt;&#x3D; w)
                dp[i][j] &#x3D; max(dp[i-1][j], dp[i-1][j-w] + v);
            else
                dp[i][j] &#x3D; dp[i-1][j];
    &#125;
    return dp[N][W];
&#125;
&#x2F;&#x2F; 空间压缩后
int knapsack(vector&lt;int&gt; weights, vector&lt;int&gt; values, int N, int W) &#123;
    vector&lt;int&gt; dp(W + 1, 0);
    for (int i &#x3D; 1; i &lt;&#x3D; N; ++i) &#123;
        int w &#x3D; weights[i-1], v &#x3D; values[i-1];
        for (int j &#x3D; W; j &gt;&#x3D; w; --j)
        	dp[j] &#x3D; max(dp[j], dp[j-w] + v);
    &#125;
    return dp[W];
&#125;



