int m,n;
queue&lt;pair&lt;int,int&gt;&gt; point; &#x2F;&#x2F;BFS
vector&lt;int&gt; direction&#123;-1, 0, 1, 0, -1&#125;; &#x2F;&#x2F;当前坐标的上下左右
void dfs(vector&lt;vector&lt;int&gt;&gt;&amp; grid,int i,int j)&#123;
    if(i&lt;0||j&lt;0 || i&gt;&#x3D;m||j&gt;&#x3D;n || grid[i][j]&#x3D;&#x3D;2) return;
    if(grid[i][j]&#x3D;&#x3D;0)&#123;
        point.push(&#123;i,j&#125;); return;
    &#125;
    grid[i][j] &#x3D; 2;
    for(int k&#x3D;0;k&lt;4;++k)&#123;
        dfs(grid,i+direction[k],j+direction[k+1]);
    &#125;
&#125;
int bfs(vector&lt;vector&lt;int&gt;&gt;&amp; grid)&#123;
    int level &#x3D; 0;
    while(!point.empty())&#123;
        level++;
        int k &#x3D; point.size();
        while(k--)&#123;
            auto [i,j] &#x3D; point.front(); point.pop();
            for(int x&#x3D;0;x&lt;4;++x)&#123;
                int r&#x3D;i+direction[x], c&#x3D;j+direction[x+1];
                if(r&gt;&#x3D;0 &amp;&amp; c&gt;&#x3D;0 &amp;&amp; r&lt;m &amp;&amp; c&lt;n)&#123;
                    if(grid[r][c]&#x3D;&#x3D;1) return level;
                    if(grid[r][c]&#x3D;&#x3D;2) continue;
                    grid[r][c] &#x3D; 2;
                    point.push(&#123;r,c&#125;);
                &#125;
            &#125;
        &#125;
    &#125;
    return 0;
&#125;
int shortestBridge(vector&lt;vector&lt;int&gt;&gt;&amp; grid) &#123;
    m&#x3D;grid.size(),n&#x3D;grid[0].size();    
    bool find &#x3D; false;
    int i,j;
    for(i&#x3D;0;i&lt;m;++i)&#123;
        for(j&#x3D;0;j&lt;n;++j)
            if(grid[i][j])&#123;
                find &#x3D; true; break;
            &#125;
        if(find) break;
    &#125;
    dfs(grid,i,j);
    return bfs(grid);
&#125;



