两个诀窍，一是按引用传状态，二是所有的状态修改在递归完成后回改。两种情况，一种是修改最后一位输出，如排列组合；一种是修改访问标记，如矩阵里搜字符串
1. N 皇后：如何将 n 个皇后放置在 n×n 的棋盘上，使得横竖斜直线上均仅一个皇后
题解：实质从0到n-1行依次选择一个位置，选择前修改矩阵，退出dfs后恢复修改。另需设置set集合记录哪些行列已存在皇后。

Click to see more
输入：n &#x3D; 4
输出：[[&quot;.Q..&quot;,&quot;...Q&quot;,&quot;Q...&quot;,&quot;..Q.&quot;],[&quot;..Q.&quot;,&quot;Q...&quot;,&quot;...Q&quot;,&quot;.Q..&quot;]]
解释：两个不同的解法

vector&lt;string&gt; cur;
vector&lt;vector&lt;string&gt;&gt; ans;
set&lt;int&gt; row, bias1, bias2;
int N;

void dfs(int i)&#123;
    if(i&gt;&#x3D;N)&#123;
        ans.push_back(cur); return;
    &#125;
    for(int j&#x3D;0;j&lt;N;++j)&#123;
        if(!row.count(j) &amp;&amp; !bias1.count(j-i) &amp;&amp; !bias2.count(j+i))&#123;
            &#x2F;&#x2F; 修改状态
            cur[i][j] &#x3D; &#39;Q&#39;; row.insert(j); bias1.insert(j-i); bias2.insert(j+i);
            &#x2F;&#x2F; 递归子结点
            dfs(i+1);
            &#x2F;&#x2F; 恢复状态
            cur[i][j] &#x3D; &#39;.&#39;; row.erase(j); bias1.erase(j-i); bias2.erase(j+i);
        &#125;
    &#125;
&#125;
vector&lt;vector&lt;string&gt;&gt; solveNQueens(int n) &#123;
    N &#x3D; n;
    cur &#x3D; vector&lt;string&gt;(n,string(n,&#39;.&#39;));
    dfs(0);
    return ans;
&#125;



2. 全排列 II：序列包含重复数字，按任意顺序返回所有不重复的全排列。
题解：

如[1,1,2]的全排列，先选第一个位置有3种选择，通过swap()实现修改与恢复；再选第二个位置，仅能从后两个里2种选择……因此只需传递i参数就能确定每次DFS中的选择
重复情况，在第一个位置，该层迭代可选择1,1,2，其中两个1导致了重复，因此需加判断使每层不选取重复值


Click to see more
vector&lt;vector&lt;int&gt;&gt; ans;
void dfs(vector&lt;int&gt;&amp; nums, int i)&#123;
    if(i&#x3D;&#x3D;nums.size())&#123;
        ans.push_back(nums);
    &#125;
    &#x2F;&#x2F; 记录该层是否选过了，-10&lt;nums[i]&lt;10
    vector&lt;bool&gt; v(20,false);
    for(int j&#x3D;i;j&lt;nums.size();j++)&#123;
        if(v[nums[j]+10]) continue;
        v[nums[j]+10] &#x3D; true;
        swap(nums[i],nums[j]);
        dfs(nums,i+1);
        swap(nums[i],nums[j]);
    &#125;
&#125;
vector&lt;vector&lt;int&gt;&gt; permuteUnique(vector&lt;int&gt;&amp; nums) &#123;
    dfs(nums,0);            
    return ans;
&#125;



